(()=>{document.querySelectorAll('.nav-link').forEach(link=>{link.addEventListener('click',function(e){e.preventDefault();document.querySelectorAll('.nav-link').forEach(item=>{item.classList.remove('active');});this.classList.add('active');const targetId=this.getAttribute('href');if(targetId!=='#'){const targetElement=document.querySelector(targetId);if(targetElement){targetElement.scrollIntoView({behavior:'smooth',block:'start'});}}});});window.addEventListener('scroll',function(){const hexagrams=document.querySelectorAll('.hexagram-card');let currentId='';hexagrams.forEach(hexagram=>{const rect=hexagram.getBoundingClientRect();if(rect.top<=100&&rect.bottom>=100){currentId=`#${hexagram.id}`;}});document.querySelectorAll('.nav-link').forEach(link=>{link.classList.remove('active');if(link.getAttribute('href')===currentId){link.classList.add('active');}});});})();;(()=>{const searchInput=document.getElementById('hexagramSearch');if(!searchInput)return;searchInput.addEventListener('input',function(){const keyword=this.value.trim().toLowerCase();document.querySelectorAll('.hexagram-card').forEach(card=>{const title=card.querySelector('.hexagram-title');if(!title)return;const name=title.textContent.toLowerCase();if(!keyword||name.includes(keyword)){card.style.display='';}else{card.style.display='none';}});});})();